from __future__ import annotations

from dataclasses import dataclass, field
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional, Sequence, Tuple

from src.trader.execution.opportunity_candidate import (
    OpportunityCandidate,
    OpportunityCandidateError,
    normalize_opportunity_candidate,
)
from src.trader.execution.opportunity_candidate_store import (
    OpportunityCandidateStoreError,
    OpportunityCandidateStoreRecord,
)


class ScannerSnapshotError(RuntimeError):
    """Raised when scanner snapshot inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ScannerSnapshotError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise ScannerSnapshotError(f"{name} must be a non-negative integer")
    if value < 0:
        raise ScannerSnapshotError(f"{name} must be a non-negative integer")
    return value


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise ScannerSnapshotError(f"{name} must be a list when provided")
    return [_require_non_empty_string(f"{name}[]", item) for item in value]


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise ScannerSnapshotError("metadata must be a mapping when provided")
    return dict(value)


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


def _normalize_candidate(value: Any) -> OpportunityCandidate:
    if isinstance(value, OpportunityCandidate):
        return value
    try:
        return normalize_opportunity_candidate(value)
    except OpportunityCandidateError as exc:
        raise ScannerSnapshotError("candidate could not be normalized") from exc


def _normalize_store_record(value: Any) -> OpportunityCandidateStoreRecord:
    if isinstance(value, OpportunityCandidateStoreRecord):
        return value
    if not isinstance(value, Mapping):
        raise ScannerSnapshotError("store_record must be a mapping or store record")
    try:
        return OpportunityCandidateStoreRecord.from_dict(value)
    except (OpportunityCandidateStoreError, OpportunityCandidateError) as exc:
        raise ScannerSnapshotError("store_record could not be normalized") from exc


@dataclass(frozen=True)
class ScannerSnapshotChainSummary:
    chain: str
    candidate_count: int

    def __post_init__(self) -> None:
        chain = _require_non_empty_string("chain", self.chain).lower()
        candidate_count = _normalize_non_negative_int("candidate_count", self.candidate_count)
        if candidate_count <= 0:
            raise ScannerSnapshotError("candidate_count must be positive for chain summaries")

        object.__setattr__(self, "chain", chain)
        object.__setattr__(self, "candidate_count", candidate_count)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "chain": self.chain,
            "candidate_count": self.candidate_count,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "ScannerSnapshotChainSummary":
        if not isinstance(payload, Mapping):
            raise ScannerSnapshotError("chain summary payload must be a mapping")
        return cls(
            chain=payload.get("chain"),
            candidate_count=payload.get("candidate_count"),
        )


@dataclass(frozen=True)
class ScannerSnapshot:
    scanner_run_id: str
    candidate_count: int
    earliest_observed_at_utc: str
    latest_observed_at_utc: str
    candidates: List[OpportunityCandidate] = field(default_factory=list)
    chain_summaries: List[ScannerSnapshotChainSummary] = field(default_factory=list)
    tags: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    scanner_snapshot_id: str = field(init=False)

    def __post_init__(self) -> None:
        scanner_run_id = _require_non_empty_string("scanner_run_id", self.scanner_run_id)
        candidate_count = _normalize_non_negative_int("candidate_count", self.candidate_count)
        earliest_observed_at_utc = _require_non_empty_string(
            "earliest_observed_at_utc",
            self.earliest_observed_at_utc,
        )
        latest_observed_at_utc = _require_non_empty_string(
            "latest_observed_at_utc",
            self.latest_observed_at_utc,
        )
        candidates = [_normalize_candidate(candidate) for candidate in self.candidates]
        chain_summaries = [
            summary if isinstance(summary, ScannerSnapshotChainSummary)
            else ScannerSnapshotChainSummary.from_dict(summary)
            for summary in self.chain_summaries
        ]
        tags = _normalize_string_list("tags", self.tags)
        metadata = _normalize_metadata(self.metadata)

        if not candidates:
            raise ScannerSnapshotError("scanner snapshot must contain at least one candidate")

        for candidate in candidates:
            if candidate.lineage.scanner_run_id != scanner_run_id:
                raise ScannerSnapshotError(
                    "all candidates in a scanner snapshot must share scanner_run_id"
                )

        if candidate_count != len(candidates):
            raise ScannerSnapshotError("candidate_count must match the number of candidates")

        observed_values = [candidate.observed_at_utc for candidate in candidates]
        if earliest_observed_at_utc != min(observed_values):
            raise ScannerSnapshotError(
                "earliest_observed_at_utc must match the earliest candidate observation"
            )
        if latest_observed_at_utc != max(observed_values):
            raise ScannerSnapshotError(
                "latest_observed_at_utc must match the latest candidate observation"
            )

        derived_chain_counts: Dict[str, int] = {}
        for candidate in candidates:
            derived_chain_counts[candidate.chain] = derived_chain_counts.get(candidate.chain, 0) + 1

        if not chain_summaries:
            chain_summaries = [
                ScannerSnapshotChainSummary(chain=chain, candidate_count=count)
                for chain, count in sorted(derived_chain_counts.items())
            ]
        else:
            provided_chain_counts = {summary.chain: summary.candidate_count for summary in chain_summaries}
            if provided_chain_counts != dict(sorted(derived_chain_counts.items())):
                raise ScannerSnapshotError(
                    "chain_summaries must match the candidate chain distribution"
                )

        object.__setattr__(self, "scanner_run_id", scanner_run_id)
        object.__setattr__(self, "candidate_count", candidate_count)
        object.__setattr__(self, "earliest_observed_at_utc", earliest_observed_at_utc)
        object.__setattr__(self, "latest_observed_at_utc", latest_observed_at_utc)
        object.__setattr__(self, "candidates", candidates)
        object.__setattr__(self, "chain_summaries", chain_summaries)
        object.__setattr__(self, "tags", tags)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "scanner_snapshot_id",
            _stable_id(
                "scanner_snapshot",
                {
                    "scanner_run_id": scanner_run_id,
                    "candidate_count": candidate_count,
                    "earliest_observed_at_utc": earliest_observed_at_utc,
                    "latest_observed_at_utc": latest_observed_at_utc,
                    "candidate_ids": [candidate.opportunity_candidate_id for candidate in candidates],
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "scanner_run_id": self.scanner_run_id,
            "candidate_count": self.candidate_count,
            "earliest_observed_at_utc": self.earliest_observed_at_utc,
            "latest_observed_at_utc": self.latest_observed_at_utc,
            "candidates": [candidate.to_dict() for candidate in self.candidates],
            "chain_summaries": [summary.to_dict() for summary in self.chain_summaries],
            "tags": list(self.tags),
            "metadata": dict(self.metadata),
            "scanner_snapshot_id": self.scanner_snapshot_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "ScannerSnapshot":
        if not isinstance(payload, Mapping):
            raise ScannerSnapshotError("scanner snapshot payload must be a mapping")
        return cls(
            scanner_run_id=payload.get("scanner_run_id"),
            candidate_count=payload.get("candidate_count"),
            earliest_observed_at_utc=payload.get("earliest_observed_at_utc"),
            latest_observed_at_utc=payload.get("latest_observed_at_utc"),
            candidates=list(payload.get("candidates") or []),
            chain_summaries=list(payload.get("chain_summaries") or []),
            tags=list(payload.get("tags") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_scanner_snapshot(value: Any) -> ScannerSnapshot:
    if isinstance(value, ScannerSnapshot):
        return value
    if not isinstance(value, Mapping):
        raise ScannerSnapshotError("scanner snapshot must be a mapping or ScannerSnapshot")
    return ScannerSnapshot.from_dict(value)


def build_scanner_snapshot(
    *,
    scanner_run_id: Any,
    candidates: Sequence[Any],
    tags: Optional[List[str]] = None,
    metadata: Optional[Mapping[str, Any]] = None,
) -> ScannerSnapshot:
    normalized_scanner_run_id = _require_non_empty_string("scanner_run_id", scanner_run_id)
    normalized_candidates = [_normalize_candidate(candidate) for candidate in candidates]

    if not normalized_candidates:
        raise ScannerSnapshotError("scanner snapshot must contain at least one candidate")

    observed_values = [candidate.observed_at_utc for candidate in normalized_candidates]

    return ScannerSnapshot(
        scanner_run_id=normalized_scanner_run_id,
        candidate_count=len(normalized_candidates),
        earliest_observed_at_utc=min(observed_values),
        latest_observed_at_utc=max(observed_values),
        candidates=list(normalized_candidates),
        chain_summaries=[],
        tags=list(tags or []),
        metadata=dict(metadata or {}),
    )


def build_scanner_snapshot_from_store_records(
    *,
    scanner_run_id: Any,
    store_records: Sequence[Any],
    tags: Optional[List[str]] = None,
    metadata: Optional[Mapping[str, Any]] = None,
) -> ScannerSnapshot:
    normalized_scanner_run_id = _require_non_empty_string("scanner_run_id", scanner_run_id)
    normalized_records = [_normalize_store_record(record) for record in store_records]

    if not normalized_records:
        raise ScannerSnapshotError("scanner snapshot must contain at least one store record")

    candidates: List[OpportunityCandidate] = []
    for record in normalized_records:
        if record.scanner_run_id != normalized_scanner_run_id:
            raise ScannerSnapshotError(
                "all store records in a scanner snapshot must share scanner_run_id"
            )
        candidates.append(record.candidate)

    return build_scanner_snapshot(
        scanner_run_id=normalized_scanner_run_id,
        candidates=candidates,
        tags=tags,
        metadata=metadata,
    )


def build_scanner_snapshot_metadata(snapshot: Any) -> Dict[str, Any]:
    normalized_snapshot = normalize_scanner_snapshot(snapshot)
    return {
        "scanner_snapshot_id": normalized_snapshot.scanner_snapshot_id,
        "scanner_run_id": normalized_snapshot.scanner_run_id,
        "candidate_count": normalized_snapshot.candidate_count,
        "chains": [summary.to_dict() for summary in normalized_snapshot.chain_summaries],
        "earliest_observed_at_utc": normalized_snapshot.earliest_observed_at_utc,
        "latest_observed_at_utc": normalized_snapshot.latest_observed_at_utc,
    }
